'use client';

import { useContext } from 'react';
import AsidemenuContext from '@/contexts/asidemenuContext';

export const useAsidemenu = () => {
  const ctx = useContext(AsidemenuContext);
  if (!ctx)
    throw new Error(
      'useAsidemenu deve ser usado dentro de <AsidemenuProvider>'
    );
  return ctx;
};
